    /**
     * Safely cleans up files in a directory that are older than the cutoff time.
     * Validates that the directory is within our app's private storage.
     */
    private fun cleanupDirectory(directoryPath: String, cutoffTime: Long, taskId: String) {
        val directory = java.io.File(directoryPath)

        // Security: Ensure we're only operating within our app's private directories
        val appDataDir = applicationInfo.dataDir
        val canonicalPath = directory.canonicalPath
        if (!canonicalPath.startsWith(appDataDir)) {
            Log.e(TAG, "[$taskId] Attempted to clean directory outside app storage: $canonicalPath")
            return
        }

        if (!directory.exists() || !directory.isDirectory) {
            Log.d(TAG, "[$taskId] Directory does not exist or is not a directory: $canonicalPath")
            return
        }

        var deletedCount = 0
        var totalSize = 0L

        directory.listFiles()?.forEach { file ->
            try {
                // Double-check canonical path to prevent symlink attacks
                val fileCanonicalPath = file.canonicalPath
                if (!fileCanonicalPath.startsWith(appDataDir)) {
                    Log.w(TAG, "[$taskId] Skipping file outside app storage: $fileCanonicalPath")
                    return@forEach
                }

                if (file.isFile && file.lastModified() < cutoffTime) {
                    val fileSize = file.length()
                    if (file.delete()) {
                        deletedCount++
                        totalSize += fileSize
                        Log.d(TAG, "[$taskId] Deleted: ${file.name} (${fileSize} bytes)")
                    }
                }
            } catch (e: SecurityException) {
                Log.w(TAG, "[$taskId] Permission denied for file: ${file.name}", e)
            } catch (e: Exception) {
                Log.w(TAG, "[$taskId] Error processing file: ${file.name}", e)
            }
        }

        Log.i(TAG, "[$taskId] Cleanup summary: deleted $deletedCount files, freed $totalSize bytes")
    }

    /**
     * Removes old completed/failed task records to prevent memory leaks.
     */
    private fun cleanupOldTaskRecords() {
        val maxAge = 3600_000L // 1 hour
        val now = System.currentTimeMillis()

        val iterator = activeTasks.entries.iterator()
        while (iterator.hasNext()) {
            val entry = iterator.next()
            val task = entry.value
            if ((task.status == TaskStatus.COMPLETED || task.status == TaskStatus.FAILED) &&
                (now - task.startTime > maxAge)
            ) {
                iterator.remove()
            }
        }
    }
